SpectremDirector.Camera={active=false,presets={}}
function SpectremDirector.Camera.toggle() local C=SpectremDirector.Camera;C.active=not C.active;if not C.active then RenderScriptCams(false,true,200,true,true);if C.handle then DestroyCam(C.handle) end;return end;C.handle=CreateCam('DEFAULT_SCRIPTED_CAMERA',true);local p=GetGameplayCamCoord();SetCamCoord(C.handle,p.x,p.y,p.z);SetCamRot(C.handle,GetGameplayCamRot(2),2);RenderScriptCams(true,true,200,true,true);CreateThread(function()while C.active do local p=GetCamCoord(C.handle);local f=GetCamForwardVector(C.handle);if IsControlPressed(0,32) then p=p+f*.04 elseif IsControlPressed(0,33) then p=p-f*.04 end;SetCamCoord(C.handle,p.x,p.y,p.z);SetCamRot(C.handle,GetCamRot(C.handle,2).x-GetDisabledControlNormal(0,2)*6,0,GetCamRot(C.handle,2).z-GetDisabledControlNormal(0,1)*6,2);Wait(0) end end) end
